public class MockDemo {
    interface EmailService { boolean send(String to, String msg); }
    static class UserService {
        EmailService emailService;
        UserService(EmailService e) { emailService = e; }
        boolean register(String email) {
            if (email == null) return false;
            return emailService.send(email, "Welcome!");
        }
    }
    public static void main(String[] args) {
        // manual mock
        EmailService mock = (to, msg) -> { System.out.println("sent to: " + to); return true; };
        UserService svc = new UserService(mock);
        System.out.println(svc.register("alice@example.com"));
        System.out.println(svc.register(null));
    }
}
